+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname, resolve } from 'pathe'
+import type { DurationObservation } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) return [{ duration: value, recordedAt: 0 }]
+  if (!value || typeof value !== 'object') return null
+  const values = 'observations' in value ? (value as { observations: unknown }).observations : [value]
+  if (!Array.isArray(values)) return null
+  return values.filter((item): item is DurationObservation => !!item && typeof item === 'object'
+    && Number.isFinite((item as DurationObservation).duration) && Number.isFinite((item as DurationObservation).recordedAt))
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(resolve(root, path), 'utf8')) as Record<string, unknown>
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const expires = Date.now() - ttl
+    return Object.fromEntries(Object.entries(raw).flatMap(([key, value]) => {
+      const entries = observations(value)
+      if (!entries) return []
+      return [[key, ttl > 0 ? entries.filter(item => item.recordedAt === 0 || item.recordedAt >= expires) : entries]]
+    }))
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(root: string, path: string, updates: Record<string, number>, maxRuns: number): Promise<void> {
+  const current = await readDurationHistory(root, path, 0) || {}
+  const now = Date.now()
+  for (const [file, duration] of Object.entries(updates)) {
+    const values = [...(current[file] || []), { duration: Math.round(duration), recordedAt: now }]
